{"content":"import type { Metadata } from 'next';
import Link from 'next/link';
import { notFound } from 'next/navigation';
import { getAllPosts, getPostById, getPostComments, type Comment } from '@/lib/posts';

interface BlogPostPageProps {
  params: Promise<{ id: string }>;
}

export async function generateStaticParams(): Promise<Array<{ id: string }>> {
  const posts = await getAllPosts();

  return posts.slice(0, 10).map((post) => ({
    id: post.id.toString(),
  }));
}

export async function generateMetadata({ params }: BlogPostPageProps): Promise<Metadata> {
  try {
    const { id } = await params;
    const post = await getPostById(id);

    return {
      title: post.title,
      description: post.body.substring(0, 160),
      openGraph: {
        title: post.title,
        description: post.body.substring(0, 160),
      },
    };
  } catch {
    return {
      title: 'Post Not Found',
    };
  }
}

export const revalidate = 300;

export default async function BlogPostPage({ params }: BlogPostPageProps) {
  try {
    const { id } = await params;
    const [post, comments] = await Promise.all([getPostById(id), getPostComments(id)]);

    return (
      <article>
        <Link className="button-link" href="/blog">
          ← Back
        </Link>

        <h1>{post.title}</h1>
        <p>{post.body}</p>

        <h2>Comments ({comments.length})</h2>
        <div className="comments">
          {comments.map((comment: Comment) => (
            <div key={comment.id} className="comment">
              <h3>{comment.name}</h3>
              <p>{comment.body}</p>
              <small>By: {comment.email}</small>
            </div>
          ))}
        </div>
      </article>
    );
  } catch {
    notFound();
  }
}
